import type * as React from 'react';

import {cn} from '@/lib/utils';

import {HoverCard as HoverCardPrimitive} from 'radix-ui';

/**
 * For sighted users to preview content available behind a link.
 *
 * ### Component Props
 *
 * See [Hover Card props](https://www.radix-ui.com/primitives/docs/components/hover-card) documentation for full details.
 *
 * | Prop            | Type                        | Default |
 * | :-------------- | :-------------------------- | :------ |
 * | _defaultOpen_   | `boolean`                   | -       |
 * | _open_          | `boolean`                   | -       |
 * | _onOpenChange_  | `(open: boolean) => void`   | -       |
 * | _openDelay_     | `number`                    | `700`   |
 * | _closeDelay_    | `number`                    | `300`   |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <HoverCard>
 *   <HoverCardTrigger asChild>
 *     <a href="/profile">@username</a>
 *   </HoverCardTrigger>
 *   <HoverCardContent>
 *     <p>User profile preview content.</p>
 *   </HoverCardContent>
 * </HoverCard>
 * ```
 */
function HoverCard({
  ...props
}: React.ComponentProps<typeof HoverCardPrimitive.Root>) {
  return <HoverCardPrimitive.Root data-slot="hover-card" {...props} />;
}

/**
 * The element that triggers the hover card to open on hover.
 *
 * ### Component Props
 *
 * See [Hover Card props](https://www.radix-ui.com/primitives/docs/components/hover-card) documentation for full details.
 *
 * | Prop       | Type      | Default |
 * | :--------- | :-------- | :------ |
 * | _asChild_  | `boolean` | `false` |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <HoverCardTrigger asChild>
 *   <a href="/profile">@username</a>
 * </HoverCardTrigger>
 * ```
 */
function HoverCardTrigger({
  ...props
}: React.ComponentProps<typeof HoverCardPrimitive.Trigger>) {
  return (
    <HoverCardPrimitive.Trigger data-slot="hover-card-trigger" {...props} />
  );
}

/**
 * The component that pops out when the hover card is open. Wraps itself in a `HoverCardPortal`.
 *
 * ### Component Props
 *
 * See [Hover Card props](https://www.radix-ui.com/primitives/docs/components/hover-card) documentation for full details.
 *
 * | Prop                | Type                                       | Default     |
 * | :------------------ | :----------------------------------------- | :---------- |
 * | _asChild_           | `boolean`                                  | `false`     |
 * | _forceMount_        | `boolean`                                  | -           |
 * | _side_              | `"top" \| "right" \| "bottom" \| "left"`   | `"bottom"`  |
 * | _sideOffset_        | `number`                                   | `4`         |
 * | _align_             | `"start" \| "center" \| "end"`             | `"center"`  |
 * | _alignOffset_       | `number`                                   | `0`         |
 * | _avoidCollisions_   | `boolean`                                  | `true`      |
 * | _collisionPadding_  | `number \| Padding`                        | `0`         |
 * | _sticky_            | `"partial" \| "always"`                    | `"partial"` |
 * | _hideWhenDetached_  | `boolean`                                  | `false`     |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <HoverCardContent align="center" sideOffset={4}>
 *   <p>Preview content goes here.</p>
 * </HoverCardContent>
 * ```
 */
function HoverCardContent({
  className,
  align = 'center',
  sideOffset = 4,
  ...props
}: React.ComponentProps<typeof HoverCardPrimitive.Content>) {
  return (
    <HoverCardPrimitive.Portal data-slot="hover-card-portal">
      <HoverCardPrimitive.Content
        data-slot="hover-card-content"
        align={align}
        sideOffset={sideOffset}
        className={cn(
          'z-floating w-64 origin-(--radix-hover-card-content-transform-origin) rounded bg-popover p-4 text-sm text-popover-foreground shadow-floating ring-1 ring-border outline-hidden duration-fast ease-out data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:fade-out-0 data-closed:zoom-out-95',
          className
        )}
        {...props}
      />
    </HoverCardPrimitive.Portal>
  );
}

export {HoverCard, HoverCardTrigger, HoverCardContent};
